import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  counters: defineTable({
    runId: v.string(),
    count: v.number(),
  }).index("by_runId", ["runId"]),
});

import { mutation, query } from "convex/server";
import { v } from "convex/values";

export const get = query({
  args: { runId: v.string() },
  handler: async (ctx, args) => {
    const counter = await ctx.db
      .query("counters")
      .withIndex("by_runId", (q) => q.eq("runId", args.runId))
      .unique();

    return counter ?? null;
  },
});

export const increment = mutation({
  args: { runId: v.string() },
  handler: async (ctx, args) => {
    const counter = await ctx.db
      .query("counters")
      .withIndex("by_runId", (q) => q.eq("runId", args.runId))
      .unique();

    if (counter) {
      await ctx.db.patch(counter._id, { count: counter.count + 1 });
      return counter.count + 1;
    }

    await ctx.db.insert("counters", { runId: args.runId, count: 1 });
    return 1;
  },
});

import { useMutation, useQuery } from 'convex/react'
import { api } from '../convex/_generated/api'
import './App.css'

const runId = import.meta.env.VITE_RUN_ID

if (!runId) {
  throw new Error('Missing VITE_RUN_ID in environment')
}

function App() {
  const counter = useQuery(api.counter.get, { runId })
  const increment = useMutation(api.counter.increment)

  const count = counter?.count ?? 0
  const isLoading = counter === undefined

  return (
    <main className="app">
      <h1>Collaborative Counter</h1>
      <p className="run-id">Run ID: {runId}</p>
      <div className="count">{isLoading ? 'Loading...' : count}</div>
      <button
        type="button"
        className="increment"
        onClick={() => increment({ runId })}
        disabled={isLoading}
      >
        Increment
      </button>
    </main>
  )
}

export default App

